/**
 * Module Loader Module Public API
 *
 * Centralized exports for the Module Loader admin module.
 * Import from this file when using module loader functionality
 * from other parts of the application.
 *
 * @module modules/_core/module-loader
 *
 * @example
 * ```typescript
 * import {
 *   ModuleLoaderModule,
 *   ModuleLoaderService,
 *   moduleLoaderRoutes,
 *   type ModuleInfo,
 *   type ModuleActionResponse,
 * } from '@/modules/_core/module-loader';
 * ```
 */

// -----------------------------------------------------------------------------
// Module Definition
// -----------------------------------------------------------------------------

export { ModuleLoaderModule, default } from '@/modules/_core/module-loader/module-loader.module';
export type {
  ModuleLoaderModuleContext,
  ModuleLoaderModuleHooks,
} from '@/modules/_core/module-loader/module-loader.module';

// -----------------------------------------------------------------------------
// Service
// -----------------------------------------------------------------------------

export { ModuleLoaderService } from '@/modules/_core/module-loader/module-loader.service';

// -----------------------------------------------------------------------------
// Controller
// -----------------------------------------------------------------------------

export { ModuleLoaderController } from '@/modules/_core/module-loader/module-loader.controller';

// -----------------------------------------------------------------------------
// Routes
// -----------------------------------------------------------------------------

export {
  moduleLoaderRoutes,
  buildModuleLoaderApiPath,
  buildModuleLoaderAdminPath,
  isProtectedModuleLoaderRoute,
  moduleLoaderEndpoints,
  // Status helpers
  moduleStatusLabels,
  moduleStatusIcons,
  moduleStatusColors,
  getModuleStatusLabel,
  getModuleStatusIcon,
  getModuleStatusColor,
  // Category helpers
  moduleCategoryLabels,
  moduleCategoryIcons,
  moduleCategoryColors,
  getModuleCategoryLabel,
  getModuleCategoryIcon,
  getModuleCategoryColor,
} from '@/modules/_core/module-loader/module-loader.routes';
export type {
  ModuleLoaderRouteConfig,
  ModuleLoaderEndpointMetadata,
} from '@/modules/_core/module-loader/module-loader.routes';

// -----------------------------------------------------------------------------
// Types
// -----------------------------------------------------------------------------

// Re-export core types
export type {
  ModuleManifest,
  ModuleStatus,
  ModuleCategory,
  LoadedModule,
} from '@/modules/_core/module-loader/module-loader.types';

// Module info types
export type {
  ModuleInfo,
  ModuleSummary,
} from '@/modules/_core/module-loader/module-loader.types';

// Request types
export type {
  ModuleActivateRequest,
  ModuleDeactivateRequest,
  ModuleInstallRequest,
  ModuleUninstallRequest,
  ModuleUpgradeRequest,
} from '@/modules/_core/module-loader/module-loader.types';

// Response types
export type {
  ModuleListResponse,
  ModuleActionResponse,
  ModuleStats,
  DependencyCheckResult,
  ModuleHealthCheckResult,
} from '@/modules/_core/module-loader/module-loader.types';

// Query/Filter types
export type {
  ModuleListFilters,
  ModuleListParams,
} from '@/modules/_core/module-loader/module-loader.types';

// Event types
export type {
  ModuleActivatedEvent,
  ModuleDeactivatedEvent,
  ModuleInstalledEvent,
  ModuleUninstalledEvent,
  ModuleUpgradedEvent,
  ModuleErrorEvent,
} from '@/modules/_core/module-loader/module-loader.types';

// Hook context types
export type {
  BeforeModuleActivateContext,
  AfterModuleActivateContext,
  BeforeModuleDeactivateContext,
  AfterModuleDeactivateContext,
} from '@/modules/_core/module-loader/module-loader.types';

// Settings types
export type { ModuleLoaderSettings } from '@/modules/_core/module-loader/module-loader.types';

// Type guards
export {
  isValidModuleStatus,
  isValidModuleCategory,
  isModuleActive,
  isModuleCore,
  hasModuleError,
} from '@/modules/_core/module-loader/module-loader.types';

// Helper functions
export {
  toModuleInfo,
  toModuleSummary,
} from '@/modules/_core/module-loader/module-loader.types';
